// ProductDetails.tsx
import React, { useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { useSelector, useDispatch } from 'react-redux';
import { setProductDetails } from './../'
import productsData from '../homepage/product-listing/product.json';

// ...

const ProductDetails = () => {
  const { productId } = useParams();
  const dispatch = useDispatch();
  const product = useSelector((state) => state.product.product);

  const thisProduct = productsData.find((prod) => prod.id === Number(productId));

  useEffect(() => {
    if (thisProduct) {
      dispatch(setProductDetails(thisProduct));
    }
  }, [productId, dispatch, thisProduct]);

  // Render the product details
  if (!product) {
    return <div>Product not found</div>;
  }

  // ...

  return (
    <div className={styles.product}>
      <div className="container">
        {/* Render the product details using the data from Redux */}
        {/* ... */}
      </div>
    </div>
  );
};

export default ProductDetails;



